Method.Source:
protected void updateCustVendApproved()
{
    ETG_ARAP_MSGHEADER headerMsg;

    CustTrans custTrans;
    VendTrans vendTrans;
    ttsbegin;
    while select headerMsg where
        headerMsg.ETGIntegrationsStatus == ETGIntegrationStatus::Processed
    if(headerMsg)
    {
        select forupdate custTrans
            where custTrans.Invoice == headerMsg.ETGARAPREF
            && custTrans.Approved == NoYes::No;
        if(custTrans)
        {
            custTrans.Approved = NoYes::Yes;
            custTrans.update();

        }
        else
        {
            select forupdate vendTrans
            where vendTrans.Invoice == headerMsg.ETGARAPREF
                && vendTrans.Approved == NoYes::No;
            if(vendTrans)
            {
                vendTrans.Approved = NoYes::Yes;
                vendTrans.update();

            }
        }
    }
    ttscommit;
}
